{
  "query": "query Overview($tenantId: ID!) { overview(tenantId: $tenantId) { kpis { autonomyPct reviewQueueCount outreachToday complaintsPct commentsAuto commentsReview postsPublished postsScheduled } attention { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status } recentRuns { id tenantId type trigger status startedAt duration autoCount reviewCount retries idempotencyKey channels note trajectory { at text state } events { worker text severity ms spans { kind title ms detail } } } systemHealth { emailComplaintRate emailBounceRate gmailWarmupUsed gmailWarmupCap igPublishUsed igPublishCap checkpointStatus } feedPreview { id tenantId worker text at chip severity } } }",
  "variables": {
    "tenantId": "{{tenantId}}"
  }
}

{
  "query": "query ReviewQueue($tenantId: ID!, $filter: ActionFilter) { reviewQueue(tenantId: $tenantId, filter: $filter) { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status } }",
  "variables": {
    "tenantId": "{{tenantId}}",
    "filter": null
  }
}

{
  "query": "query Action($id: ID!) { action(id: $id) { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status } }",
  "variables": {
    "id": "{{sampleActionId}}"
  }
}

{
  "query": "query Activity($tenantId: ID!, $filter: ActionFilter) { activity(tenantId: $tenantId, filter: $filter) { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status autonomy content outcome { label kind } engagement { label value } thread { role name text } comments { name text autoReplied } runId trace { id latency model tokens } judges { name score vote reasoning } spans { kind title ms detail } links { label target targetType } } }",
  "variables": {
    "tenantId": "{{tenantId}}",
    "filter": null
  }
}

{
  "query": "query Runs($tenantId: ID!, $filter: RunFilter) { runs(tenantId: $tenantId, filter: $filter) { id tenantId type trigger status startedAt duration autoCount reviewCount retries idempotencyKey channels note trajectory { at text state } events { worker text severity ms spans { kind title ms detail } } } }",
  "variables": {
    "tenantId": "{{tenantId}}",
    "filter": null
  }
}

{
  "query": "query Run($id: ID!) { run(id: $id) { id tenantId type trigger status startedAt duration autoCount reviewCount retries idempotencyKey channels note trajectory { at text state } events { worker text severity ms spans { kind title ms detail } } } }",
  "variables": {
    "id": "{{sampleRunId}}"
  }
}

{
  "query": "query Feed($tenantId: ID!) { feed(tenantId: $tenantId) { id tenantId worker text at chip severity } }",
  "variables": {
    "tenantId": "{{tenantId}}"
  }
}

{
  "query": "query SystemHealth($tenantId: ID!) { systemHealth(tenantId: $tenantId) { emailComplaintRate emailBounceRate gmailWarmupUsed gmailWarmupCap igPublishUsed igPublishCap checkpointStatus } }",
  "variables": {
    "tenantId": "{{tenantId}}"
  }
}

{
  "query": "mutation ApproveAction($id: ID!, $idempotencyKey: String!) { approveAction(id: $id, idempotencyKey: $idempotencyKey) { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status } }",
  "variables": {
    "id": "{{sampleActionId}}",
    "idempotencyKey": "{{idempotencyKey}}"
  }
}

{
  "query": "mutation RejectAction($id: ID!, $reason: String) { rejectAction(id: $id, reason: $reason) { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status } }",
  "variables": {
    "id": "{{sampleActionId}}",
    "reason": "not on-brand"
  }
}

{
  "query": "mutation EditActionDraft($id: ID!, $draft: String!) { editActionDraft(id: $id, draft: $draft) { id tenantId type channel worker target createdAt subject context draft confidence threshold escalation { kind label } jury { confidence threshold agreement dimensions { label score } } gates { label ok } recommendation idempotencyKey status } }",
  "variables": {
    "id": "{{sampleActionId}}",
    "draft": "Edited draft text from Postman."
  }
}
